mapper.insert:
insert into hx_story_like(
    story_id, user_id, user_name, create_time
) values (
    #{storyId}, #{userId}, #{userName}, #{createTime}
)

mapper.select:
select 
    DATE(create_time) as date,
    COUNT(*) as count
from hx_story_like
where user_id = #{userId}
  and create_time >= #{startDate}
  and create_time <= #{endDate}
group by DATE(create_time)
order by date asc

select 
    HOUR(create_time) as hour,
    COUNT(*) as count
from hx_story_like
where user_id = #{userId}
  and create_time >= #{startDate}
  and create_time <= #{endDate}
group by HOUR(create_time)
order by hour asc
